import type { Metadata } from "next";

import { getForecastPortfolioSurface } from "@/lib/forecastPortfolioData";
import { SITE } from "@/lib/site";
import { requireTenantContext } from "@/lib/tenant";

import { addWatchedMarket } from "./actions";
import ForecastPortfolioView from "./ForecastPortfolioView";

export const dynamic = "force-dynamic";

type SearchParams = Record<string, string | string[] | undefined>;

export const metadata: Metadata = {
  title: "Theseus - Forecasts portfolio",
  description: "Paper prediction-market positions, forecast traces, and live-trading gate state.",
  openGraph: {
    description: "Paper prediction-market positions, forecast traces, and live-trading gate state.",
    siteName: "Theseus Codex",
    title: "Theseus - Forecasts portfolio",
    type: "website",
    url: `${SITE}/forecasts/portfolio`,
  },
};

function firstParam(value: string | string[] | undefined): string | null {
  if (Array.isArray(value)) return value[0] ?? null;
  return value ?? null;
}

function watchState(value: string | null): "added" | "invalid" | "unsupported" | null {
  if (value === "added" || value === "invalid" || value === "unsupported") return value;
  return null;
}

export default async function ForecastsPortfolioPage({
  searchParams,
}: {
  searchParams: Promise<SearchParams>;
}) {
  const tenant = await requireTenantContext();
  if (!tenant) return null;

  const params = await searchParams;
  const surface = await getForecastPortfolioSurface(tenant.organizationId);

  return (
    <ForecastPortfolioView
      addWatchedMarketAction={addWatchedMarket}
      surface={surface}
      watchState={watchState(firstParam(params.watch))}
    />
  );
}

generator client {
  provider = "prisma-client-js"
  // No custom `output` — Prisma 7 puts types alongside the runtime at
  // `node_modules/.prisma/client` automatically when you leave this blank,
  // and `@prisma/client` re-exports them. Explicitly setting
  // `output = "../node_modules/.prisma/client"` used to work on Prisma 6
  // but in Prisma 7 it only emits the WASM runtime (no .d.ts files),
  // which breaks every `import { PrismaClient } from "@prisma/client"`.
}

// Postgres everywhere (Supabase / Neon / local Docker Postgres). Prisma bakes
// the provider into the generated migrations, so you can't switch to SQLite
// per-env with the same migration history. Use a local Postgres container
// (see `docker-compose.dev.yml`) for offline dev, or point DATABASE_URL at
// your Supabase project for both dev and prod.
datasource db {
  provider = "postgresql"
}

