    self, resolution_id: str
) -> list[ResolutionRevision]:
    with self.session() as s:
        return list(
            s.exec(
                select(ResolutionRevision)
                .where(ResolutionRevision.resolution_id == resolution_id)
                .order_by(asc(ResolutionRevision.created_at))
            ).all()
        )

